#!/usr/bin/env node

/**
 * GAS ファイル結合スクリプト
 *
 * gas/ フォルダ内の複数の GAS ソースファイルを1つの Bundle.gs に結合します。
 * 開発時は分割ファイルで作業し、デプロイ時に結合することで、
 * コードの見通しと実行効率を両立させます。
 */

const fs = require('fs');
const path = require('path');

// パス設定
const GAS_SOURCE_DIR = path.join(__dirname, '..');  // gas/scripts/.. → gas
const DIST_DIR = path.join(__dirname, '..', '..', 'dist');  // gas/scripts/../../dist → dist
const OUTPUT_FILE = path.join(DIST_DIR, 'Bundle.gs');

// 結合順序（依存関係順）
const FILE_ORDER = [
  'constants.gs',
  'errors.gs',           // エラーハンドリング・レスポンス共通
  'adminAuth.gs',        // 管理者キー / 管理者メール / Google Group メンバーシップ / 管理者判定
  'settings.gs',         // 一般設定（restrictToFormOnly / DetermineAccess_ / 公開 API ラッパー）
  'properties.gs',       // プロパティサービス管理
  'schemaUtils.gs',      // pure schema walkers (nfbTraverseSchema_ など)
  // --- alasql ランタイム + UDF + 式評価器・テンプレート（driveTemplate より前） ---
  'vendor/alasql.min.js',       // alasql 本体（グローバル alasql）
  'generated/nfbAlasqlUdfs.gs', // builder ESM ソースから esbuild 生成（UDF / 日付ユーティリティ）
  'expressionEvaluator.gs', // alasql ラッパー（単行式評価 + nfbDt_* 委譲）
  'templateEvaluator.gs',   // {expr} テンプレートのスキャナ + 評価
  // --- drive分割 ---
  'driveTemplate.gs',       // テンプレート解決
  'drivePrintDocument.gs',  // 印刷様式ドキュメント
  'driveFolder.gs',         // フォルダ管理
  'driveOutput.gs',         // 出力オーケストレーション（PDF/GoogleDoc）
  'driveGmailOutput.gs',    // Gmail下書き出力
  'driveFile.gs',           // ファイル操作（公開API）
  // --- forms ---
  'formsParsing.gs',
  'formsMappingStore.gs',
  'formsFolderStore.gs',
  'formsTitleHelpers.js',
  'formsStorage.gs',
  'formsCrud.gs',
  'formsImport.gs',
  'formsPublicApi.gs',
  'analyticsApi.gs',     // アナリティクス API（Question/Dashboard）— 定数・マッピング・公開ラッパー
  'analyticsCrud.gs',    // list / get / save / delete / archive 本体
  'analyticsImport.gs',  // Drive URL からのインポート
  'analyticsCopy.gs',         // 同フォルダへの複製
  'analyticsFolderStore.gs', // フォルダ登録簿（Analytics 版）
  'model.gs',            // モデル関数
  // --- sheets ---
  'sheetsDatetime.gs',
  'sheetsHeaders.gs',
  'sheetsRowOps.gs',
  'sheetsRecords.gs',
  'syncRecordsMerge.js',
  // --- Code分割 ---
  'codeAuth.gs',         // 認証・プロフィール
  'codeHandlers.gs',     // アクションハンドラ
  'codeSyncRecords.gs',  // 同期処理
  'Code.gs',             // メインエントリーポイント
  // --- 管理者向け移行スクリプト（Plan P4 / P5、手動実行のみ） ---
  'adminMigrations.gs',
];

/**
 * dist ディレクトリを作成
 */
function ensureDistDir() {
  if (!fs.existsSync(DIST_DIR)) {
    fs.mkdirSync(DIST_DIR, { recursive: true });
    console.log(`✅ Created directory: ${DIST_DIR}`);
  }
}

// gas/vendor/alasql.min.js の先頭に付けるセンチネル（変換済みマーカー）。
// esbuild の minify は自分自身の出力に対して厳密には冪等でない（毎回わずかに変わる）ため、
// このマーカーで「既に変換済みか」を判定し、二重変換による無意味な git 差分を防ぐ。
const ALASQL_GAS_SENTINEL = '/*! gas-lowered:es2019 — regenerated by gas/scripts/bundle.js, do not hand-edit */';

/**
 * gas/vendor/alasql.min.js を GAS の V8 ランタイムで解釈できる構文へ落とす。
 *
 * alasql 4.x の配布ビルドは private クラスメンバ（`#name`）を含むが、GAS の V8
 * パーサはこれを解釈できず、`clasp push` がサーバ側で `ParseError: Unexpected token =`
 * となって失敗する。esbuild の target=es2019 変換で `#private` は WeakMap ベースの
 * シムに降格され（`?.` / `??` 等も同時に降格）、GAS 互換になる。
 *
 * - 変換結果は冪等でないため、変換済みファイル（先頭にセンチネルあり）はそのまま使う。
 * - esbuild が無い環境では何もしない（コミット済みの変換済みファイルをそのまま使う）。
 *   ※ 上流の素の alasql を投入した直後だけは esbuild 必須（root で `npm install` 済みであること）。
 */
function lowerVendorAlasqlForGas() {
  const vendorFile = path.join(GAS_SOURCE_DIR, 'vendor', 'alasql.min.js');
  if (!fs.existsSync(vendorFile)) {
    console.warn('⚠️  gas/vendor/alasql.min.js not found, skipping ES2019 lowering...');
    return;
  }
  const src = fs.readFileSync(vendorFile, 'utf8');
  if (src.startsWith(ALASQL_GAS_SENTINEL)) {
    console.log('✓ gas/vendor/alasql.min.js already lowered for GAS V8');
    return;
  }
  let esbuild;
  try {
    esbuild = require('esbuild');
  } catch (_e) {
    console.warn('⚠️  esbuild not found and gas/vendor/alasql.min.js is NOT pre-lowered — clasp push may fail on #private. Run `npm install` at repo root.');
    return;
  }
  const { code } = esbuild.transformSync(src, {
    loader: 'js',
    target: 'es2019',
    minify: true,
    legalComments: 'inline',
  });
  fs.writeFileSync(vendorFile, ALASQL_GAS_SENTINEL + '\n' + code, 'utf8');
  console.log('✅ Lowered gas/vendor/alasql.min.js to ES2019 (GAS V8 compatible)');
}

/**
 * builder の ESM ソース (gasRuntimeEntry.js) を esbuild で IIFE バンドルし、
 * gas/generated/nfbAlasqlUdfs.gs を再生成する。esbuild が無い環境ではコミット済みの
 * 生成ファイルをそのまま使う（警告のみ）。
 */
function regenerateAlasqlUdfBundle() {
  const entry = path.join(GAS_SOURCE_DIR, '..', 'builder', 'src', 'features', 'expression', 'gasRuntimeEntry.js');
  const outfile = path.join(GAS_SOURCE_DIR, 'generated', 'nfbAlasqlUdfs.gs');
  let esbuild;
  try {
    esbuild = require('esbuild');
  } catch (_e) {
    console.warn('⚠️  esbuild not found — using committed gas/generated/nfbAlasqlUdfs.gs as-is.');
    return;
  }
  fs.mkdirSync(path.dirname(outfile), { recursive: true });
  esbuild.buildSync({
    entryPoints: [entry],
    bundle: true,
    format: 'iife',
    globalName: 'NfbAlasqlRuntime',
    platform: 'neutral',
    target: 'es2019',
    legalComments: 'none',
    outfile,
    banner: { js: '/* AUTO-GENERATED — DO NOT EDIT.\n   Source: builder/src/features/expression/gasRuntimeEntry.js\n   Regenerate: npm run build:gas-udfs */' },
  });
  console.log('✅ Regenerated gas/generated/nfbAlasqlUdfs.gs');
}

/**
 * GAS ファイルを結合
 */
function bundleGasFiles() {
  const bundledContent = [];

  // ヘッダーコメント
  bundledContent.push('/**');
  bundledContent.push(' * Nested Form Builder - GAS Bundle');
  bundledContent.push(` * Generated: ${new Date().toISOString()}`);
  bundledContent.push(' * DO NOT EDIT THIS FILE DIRECTLY');
  bundledContent.push(' * Edit source files in gas/ directory instead');
  bundledContent.push(' */');
  bundledContent.push('');

  // 各ファイルを順番に結合
  FILE_ORDER.forEach((fileName) => {
    const filePath = path.join(GAS_SOURCE_DIR, fileName);

    if (!fs.existsSync(filePath)) {
      console.warn(`⚠️  Warning: ${fileName} not found, skipping...`);
      return;
    }

    const content = fs.readFileSync(filePath, 'utf8');

    // ファイル区切りコメント
    bundledContent.push('// ' + '='.repeat(77));
    bundledContent.push(`// ${fileName}`);
    bundledContent.push('// ' + '='.repeat(77));
    bundledContent.push('');
    bundledContent.push(content.trim());
    bundledContent.push('');
  });

  // 出力
  const finalContent = bundledContent.join('\n');
  fs.writeFileSync(OUTPUT_FILE, finalContent, 'utf8');

  console.log(`✅ Bundle created: ${OUTPUT_FILE}`);
  console.log(`   Size: ${(finalContent.length / 1024).toFixed(2)} KB`);
  console.log(`   Files bundled: ${FILE_ORDER.length}`);
}

/**
 * メイン処理
 */
function main() {
  try {
    ensureDistDir();
    lowerVendorAlasqlForGas();
    regenerateAlasqlUdfBundle();
    bundleGasFiles();
    console.log('🎉 GAS bundling completed successfully!');
  } catch (error) {
    console.error('❌ Error during bundling:', error.message);
    process.exit(1);
  }
}

// 実行
main();
